import{bQ as i,aL as a,u as e,G as t}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"10｜grep 过滤与正则","description":"","frontmatter":{},"headers":[],"relativePath":"02.Shell脚本/10-grep过滤与正则.md","filePath":"02.Shell脚本/10-grep过滤与正则.md","lastUpdated":null}'),p={name:"02.Shell脚本/10-grep过滤与正则.md"};function n(l,s,h,d,r,k){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="_10-grep-过滤与正则" tabindex="-1">10｜grep 过滤与正则 <a class="header-anchor" href="#_10-grep-过滤与正则" aria-label="Permalink to &quot;10｜grep 过滤与正则&quot;">​</a></h1><p>Linux 基础系列里用管道串过 grep——<code>cat log | grep error</code> 从日志里找含 error 的行。那是最基础的用法。本篇深入讲 grep 的正则语法和常用参数，写脚本时能更精确地过滤文本。</p><h2 id="一、grep-做什么" tabindex="-1">一、grep 做什么 <a class="header-anchor" href="#一、grep-做什么" aria-label="Permalink to &quot;一、grep 做什么&quot;">​</a></h2><p>grep 按模式匹配文本行，把匹配的行输出。最简单的用法：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> error</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/messages</span></span></code></pre></div><p>从 <code>/var/log/messages</code> 找含 &quot;error&quot; 的行。&quot;error&quot; 是最简单的模式——普通字符串，逐字匹配。</p><h2 id="二、基础正则" tabindex="-1">二、基础正则 <a class="header-anchor" href="#二、基础正则" aria-label="Permalink to &quot;二、基础正则&quot;">​</a></h2><p>模式里用特殊字符表示一类字符，这就是正则：</p><table tabindex="0"><thead><tr><th>符号</th><th>匹配</th></tr></thead><tbody><tr><td><code>.</code></td><td>任意一个字符</td></tr><tr><td><code>*</code></td><td>前一个字符出现 0 次或多次</td></tr><tr><td><code>^</code></td><td>行首</td></tr><tr><td><code>$</code></td><td>行尾</td></tr><tr><td><code>[abc]</code></td><td>abc 中任一个</td></tr><tr><td><code>[^abc]</code></td><td>不是 abc 的任一个</td></tr></tbody></table><p>例子：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 找以 ERROR 开头的行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;^ERROR&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.log</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 找以 .log 结尾的行（注意 . 在正则里是任意字符，这里要转义）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;\\.log$&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> files.txt</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 找 IP 地址（粗略）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;[0-9]\\.[0-9]\\.[0-9]\\.[0-9]&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> access.log</span></span></code></pre></div><p>注意 <code>.</code> 在正则里是&quot;任意字符&quot;，要匹配字面的点要加反斜杠转义 <code>\\.</code>。这是初学常犯的错——写 <code>grep .log</code> 会匹配到 &quot;xlog&quot;&quot;alog&quot; 之类。</p><h2 id="三、扩展正则-e" tabindex="-1">三、扩展正则 -E <a class="header-anchor" href="#三、扩展正则-e" aria-label="Permalink to &quot;三、扩展正则 -E&quot;">​</a></h2><p>基础正则里 <code>+</code>、<code>?</code>、<code>|</code>、<code>()</code> 这些要转义。用 <code>-E</code>（或 <code>egrep</code>）启用扩展正则，这些字符直接能用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 找 ERROR 或 WARN</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;ERROR|WARN&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.log</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 找连续数字（+ 表示一次或多次）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;[0-9]+&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> access.log</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 分组</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;(error|fail)&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.log</span></span></code></pre></div><p>写复杂正则一律用 <code>-E</code>，少写很多反斜杠。</p><h2 id="四、常用参数" tabindex="-1">四、常用参数 <a class="header-anchor" href="#四、常用参数" aria-label="Permalink to &quot;四、常用参数&quot;">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>作用</th></tr></thead><tbody><tr><td><code>-i</code></td><td>忽略大小写</td></tr><tr><td><code>-v</code></td><td>反向匹配（输出不匹配的行）</td></tr><tr><td><code>-n</code></td><td>显示行号</td></tr><tr><td><code>-c</code></td><td>只输出匹配行数</td></tr><tr><td><code>-l</code></td><td>只输出有匹配的文件名</td></tr><tr><td><code>-r</code></td><td>递归搜索目录</td></tr><tr><td><code>-o</code></td><td>只输出匹配的部分（不输出整行）</td></tr><tr><td><code>-A 2</code></td><td>匹配行后再显示 2 行</td></tr><tr><td><code>-B 2</code></td><td>匹配行前显示 2 行</td></tr><tr><td><code>-C 2</code></td><td>匹配行前后各 2 行</td></tr></tbody></table><p><code>-v</code> 反向匹配很常用——排除某些行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 找非注释行（不以 # 开头）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;^#&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/ssh/sshd_config</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 排除空行和注释行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;^\\s*(#|$)&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config.conf</span></span></code></pre></div><p><code>-A</code>/<code>-B</code>/<code>-C</code> 看错误上下文——报错时连带前后几行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Exception&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.log</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 异常行后看 5 行堆栈</span></span></code></pre></div><p><code>-o</code> 只取匹配部分——从日志里把所有 IP 提出来：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -oE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;[0-9]+\\.[0-9]+\\.[0-9]+\\.[0-9]+&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> access.log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sort</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span></span></code></pre></div><h2 id="五、-p-perl-正则" tabindex="-1">五、-P：Perl 正则 <a class="header-anchor" href="#五、-p-perl-正则" aria-label="Permalink to &quot;五、-P：Perl 正则&quot;">​</a></h2><p><code>-P</code> 启用 Perl 兼容正则，支持更高级特性（<code>\\d</code>、<code>\\s</code>、零宽断言）。不是所有 grep 都支持：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># \\d 匹配数字</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -P</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;\\d+\\.\\d+\\.\\d+\\.\\d+&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> access.log</span></span></code></pre></div><p>能用 <code>-E</code> 就用 <code>-E</code>，移植性更好。<code>-P</code> 在需要特殊特性时才用，且要确认环境的 grep 支持（GNU grep 支持，BSD/macOS 的不支持）。</p><h2 id="六、grep-在管道里的位置" tabindex="-1">六、grep 在管道里的位置 <a class="header-anchor" href="#六、grep-在管道里的位置" aria-label="Permalink to &quot;六、grep 在管道里的位置&quot;">​</a></h2><p>grep 经常接在管道后面过滤前一个命令的输出：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从 ps 输出找进程</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aux</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 但这样会把 grep 自己也匹配出来</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aux</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grep</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 排除 grep 自身</span></span></code></pre></div><p>更优雅的写法用 <code>grep [n]ginx</code>——模式里把一个字符放中括号，匹配的还是 nginx，但进程名显示的是 <code>grep [n]ginx</code>，不会被自己匹配：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aux</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;[n]ginx&#39;</span></span></code></pre></div><h2 id="七、性能" tabindex="-1">七、性能 <a class="header-anchor" href="#七、性能" aria-label="Permalink to &quot;七、性能&quot;">​</a></h2><p>大文件里 grep 一般很快。但有几个坑：</p><p><strong>贪心匹配</strong>——<code>.*</code> 会尽可能多匹配，可能跨过预期边界：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 想匹配 &lt;html&gt; 标签，但 .* 贪婪会匹配到最后一个 &gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&lt;.*&gt;&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file</span></span></code></pre></div><p>用非贪婪（<code>-P</code> 支持 <code>.*?</code>）或更精确的模式避免。</p><p><strong>大文件重复 grep</strong>——对同一大文件多次 grep，不如一次 awk 处理：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 慢：扫三遍</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ERROR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> log</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> WARN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> log</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> log</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 快：扫一遍</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">awk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;/ERROR/{e++} /WARN/{w++} /INFO/{i++} END{print e,w,i}&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> log</span></span></code></pre></div><h2 id="八、grep-还是-grep-e-还是-rg" tabindex="-1">八、grep 还是 grep -E 还是 rg <a class="header-anchor" href="#八、grep-还是-grep-e-还是-rg" aria-label="Permalink to &quot;八、grep 还是 grep -E 还是 rg&quot;">​</a></h2><ul><li><code>grep</code>：基础正则，移植性最好</li><li><code>grep -E</code>：扩展正则，写脚本首选</li><li><code>rg</code>（ripgrep）：更快、默认递归、默认忽略 .gitignore，但不是系统自带</li></ul><p>生产脚本要可移植用 <code>grep -E</code>。交互式搜索用 <code>rg</code> 更顺手。</p><h2 id="学会了之后" tabindex="-1">学会了之后 <a class="header-anchor" href="#学会了之后" aria-label="Permalink to &quot;学会了之后&quot;">​</a></h2><p>grep 是文本过滤的主力。正则分基础（<code>.</code>、<code>*</code>、<code>^</code>、<code>$</code>、<code>[]</code>）和扩展（<code>+</code>、<code>?</code>、<code>|</code>、<code>()</code>，用 <code>-E</code>）。常用参数里 <code>-v</code>（反向）、<code>-n</code>（行号）、<code>-A/-B/-C</code>（上下文）、<code>-o</code>（只取匹配）最高频。</p><p>下一篇讲 sed——流编辑，能对文本做替换、增删改。</p>`,46)])])}const g=i(p,[["render",n]]);export{c as __pageData,g as default};
